import{_ as a,o as n,c as s,a2 as e}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"NotPetya（2017）：伪装成勒索软件的供应链武器","description":"","frontmatter":{},"headers":[],"relativePath":"zh/cases/security/notpetya.md","filePath":"zh/cases/security/notpetya.md"}'),l={name:"zh/cases/security/notpetya.md"};function r(o,t,i,p,d,h){return n(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="notpetya-2017-伪装成勒索软件的供应链武器" tabindex="-1">NotPetya（2017）：伪装成勒索软件的供应链武器 <a class="header-anchor" href="#notpetya-2017-伪装成勒索软件的供应链武器" aria-label="Permalink to &quot;NotPetya（2017）：伪装成勒索软件的供应链武器&quot;">​</a></h1><p><strong>史上损失最大的网络攻击如何通过会计软件更新传播</strong></p><blockquote><p><strong>关联指南：</strong> <a href="/zh/security-guide.html">供应链安全合规审核指南</a> · <strong>适用行业：</strong> 跨行业（物流、制药、食品、能源）</p></blockquote><hr><h2 id="事件概述" tabindex="-1">事件概述 <a class="header-anchor" href="#事件概述" aria-label="Permalink to &quot;事件概述&quot;">​</a></h2><p>2017年6月27日，一场伪装成勒索软件的网络武器从乌克兰爆发，在数小时内蔓延至全球150余个国家，造成估计超过<strong>100亿美元</strong>的经济损失。攻击的初始入口：<strong>一款乌克兰财务软件 M.E.Doc 的自动更新机制</strong>。</p><p>美国、英国、欧盟后来将 NotPetya 归因于俄罗斯军事情报局（GRU）旗下的 Sandworm 黑客组织，定性为针对乌克兰的网络战行动，但因全球供应链的互联互通，破坏效果蔓延至全球企业。</p><hr><h2 id="传播机制" tabindex="-1">传播机制 <a class="header-anchor" href="#传播机制" aria-label="Permalink to &quot;传播机制&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GRU Sandworm → 攻破 M.E.Doc 更新服务器</span></span>
<span class="line"><span>                        ↓</span></span>
<span class="line"><span>              在合法软件更新包中植入恶意代码</span></span>
<span class="line"><span>                        ↓</span></span>
<span class="line"><span>              M.E.Doc 客户（主要为乌克兰企业）自动下载更新</span></span>
<span class="line"><span>                        ↓</span></span>
<span class="line"><span>              NotPetya 在本地网络内利用 EternalBlue（NSA泄露漏洞）横向扩散</span></span>
<span class="line"><span>                        ↓</span></span>
<span class="line"><span>              通过 VPN/专线蔓延至全球总部及子公司</span></span>
<span class="line"><span>                        ↓</span></span>
<span class="line"><span>              加密 MBR（主引导记录），设备永久无法启动</span></span></code></pre></div><p><strong>关键特征：</strong> NotPetya 没有真正的解密功能。支付赎金也无法恢复数据——它的目的是<strong>最大化破坏，而非勒索</strong>。</p><hr><h2 id="典型受害者" tabindex="-1">典型受害者 <a class="header-anchor" href="#典型受害者" aria-label="Permalink to &quot;典型受害者&quot;">​</a></h2><table tabindex="0"><thead><tr><th>企业</th><th>损失</th><th>说明</th></tr></thead><tbody><tr><td><strong>马士基（Maersk）</strong></td><td>约3亿美元</td><td>全球最大集装箱航运公司；45,000台PC、4,000台服务器全部宕机；10天无法处理新订单</td></tr><tr><td><strong>默克（Merck）</strong></td><td>约8.7亿美元</td><td>制药巨头；疫苗生产线停摆；库存损毁</td></tr><tr><td><strong>联邦快递（TNT）</strong></td><td>约4亿美元</td><td>TNT欧洲业务全面瘫痪，部分系统数月未完全恢复</td></tr><tr><td><strong>蒙迪（Mondelez）</strong></td><td>约1.8亿美元</td><td>快消品公司；工厂停产、销售系统中断</td></tr><tr><td><strong>拜耳</strong></td><td>未披露</td><td>医药公司；部分生产系统受影响</td></tr></tbody></table><hr><h2 id="马士基案例深度分析" tabindex="-1">马士基案例深度分析 <a class="header-anchor" href="#马士基案例深度分析" aria-label="Permalink to &quot;马士基案例深度分析&quot;">​</a></h2><p>马士基案例因其透明度高而成为企业网络安全韧性的重要教材。</p><h3 id="恢复过程" tabindex="-1">恢复过程 <a class="header-anchor" href="#恢复过程" aria-label="Permalink to &quot;恢复过程&quot;">​</a></h3><ul><li><strong>第1天</strong>：全球IT系统瘫痪，无法处理货物预订、追踪、清关</li><li><strong>第1–10天</strong>：依靠纸质单据和WhatsApp群组维持部分运营</li><li><strong>第10天</strong>：在加纳一个碰巧未受影响的域控制器上找到备份，以此为基础重建 Active Directory</li><li><strong>10天内</strong>：重新安装45,000台PC、4,000台服务器、2,500个应用——这相当于马士基通常<strong>需要几年</strong>才能完成的IT迁移工程</li></ul><h3 id="暴露的弱点" tabindex="-1">暴露的弱点 <a class="header-anchor" href="#暴露的弱点" aria-label="Permalink to &quot;暴露的弱点&quot;">​</a></h3><ul><li>Active Directory 只有单点（乌克兰子公司域控是全局入口）</li><li>补丁管理滞后（EternalBlue 漏洞微软已在2017年3月发布补丁，但马士基部分系统未及时更新）</li><li>网络分段不足（勒索软件可以在各业务单元之间自由横向移动）</li><li>第三方软件更新未经安全验证即自动执行</li></ul><hr><h2 id="软件供应链攻击的启示" tabindex="-1">软件供应链攻击的启示 <a class="header-anchor" href="#软件供应链攻击的启示" aria-label="Permalink to &quot;软件供应链攻击的启示&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">软件更新与第三方软件的安全管控</p><p><strong>M.E.Doc 案例的核心教训：</strong></p><ol><li><p><strong>自动更新是一把双刃剑</strong></p><ul><li>优点：及时修补安全漏洞</li><li>风险：更新包本身可能被投毒</li><li>对策：关键业务软件更新须经测试环境验证后再推送生产</li></ul></li><li><p><strong>软件供应商的安全评估</strong></p><ul><li>财务、ERP、工资等关键业务软件供应商须纳入第三方安全评估范围</li><li>要求软件供应商提供代码签名、更新完整性校验机制</li><li>高风险软件（特别是有内网访问权限的）应实施软件物料清单（SBOM）管理</li></ul></li><li><p><strong>网络分段与爆炸半径控制</strong></p><ul><li>即使一个节点被攻陷，横向扩散的路径应受到限制</li><li>乌克兰子公司与全球总部之间的VPN访问应受到严格的流量过滤</li></ul></li><li><p><strong>离线/不可变备份</strong></p><ul><li>备份须与生产网络物理隔离（&quot;气隙备份&quot;）</li><li>定期测试备份恢复时间（RTO）——马士基的教训是：从未测试过全规模恢复</li></ul></li></ol></div><hr><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>Andy Greenberg: <em>Sandworm</em> (2019) — 本书对 NotPetya 有最详尽的记录</li><li>Wired: <em>The Untold Story of NotPetya, the Most Devastating Cyberattack in History</em> (2018)</li><li>Maersk CFO: 内部复盘演讲（Copenhagen Cyber Crime Conference, 2018）</li><li>CISA/FBI: <em>Russian GRU Conducting Global Cyber Operations</em> (Advisory, 2020)</li><li>NIST SP 800-161: <em>Cybersecurity Supply Chain Risk Management</em></li></ul>`,27)])])}const g=a(l,[["render",r]]);export{u as __pageData,g as default};
